import React from 'react';
import logo from './logo.svg';
import './App.css';

class App extends React.Component {
  constructor(props) {
    super();
    this.state = {
      count: 60
    }
  }

  handleClick = () => {
    alert('funciona');
  }

  render() {
    return (
      <div className="App">
        <header className="App-header">
          <img src={logo} className="App-logo" alt="logo" />
          <p>
            Stopwatch
          </p>
          <section className="stopwatch">
            <span>{(this.state.count >= 10) ? this.state.count : "0" + this.state.count}</span>&nbsp;:&nbsp;
            <span>00</span>
          </section>
          <button onClick={this.handleClick}>Iniciar</button>
        </header>
      </div>
    );
  }

}

export default App;
